var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"3일 뒤, 국경 밖.","JPN":"3日後、国境の外。","ENG":"3 days later. Outside the border.","TWN":"3天後 國境外"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"폐쇄된 구 남부횡단열차 종착역. \\n노르드나빅 포기거점. 디어루트 외성 부근.","JPN":"閉鎖された旧南部横断列車の終着駅。\\nノルドナビックの放棄拠点。ディアルート外郭付近。","ENG":"Closed off terminal of the old Southern Transit Railway.\\nAbandoned Nordnavik Base. Nearby outer castle Deer Root.","TWN":"封鎖的舊南方縱貫列車終點站 \\n諾爾德萊比放棄據點 迪魯特外城附近"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L4_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"어엇, 물자들 쓰러지지 않게 조심해!","JPN":"おおっと、物資が倒れないように気をつけろよ！","ENG":"Hey! Be careful not to drop the supplies!","TWN":"喂，小心別弄倒物資！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_12"},{"id":"L5_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"바람도 엄청 불고, 피부가 얼어붙겠네.","JPN":"風もすごく強いし、肌が凍りそうだ。","ENG":"It's so windy out here, It feels like my skin's about to turn into ice!","TWN":"風好大，臉好冰喔！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L7_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"여긴 완전히 겨울이군. 우린 침식지대 한복판에 들어온 거야.","JPN":"ここはすっかり冬だな。俺らは侵食地帯のど真ん中に入ってきたんだ。","ENG":"It's a full-blown winter here. We just walked into the center of a Corrupted Area.","TWN":"這裡根本完全是冬天，看來我們進到侵蝕地帶的中心。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"디어루트에는 처음 와봐요. 이전에 사람이 살던 곳이라곤 믿기지 않네요.","JPN":"ディアルートは初めてですね。以前人が住んでたなんて信じられませんよ。","ENG":"It's my first time in Deer Root. I still can't believe people used to live here.","TWN":"我是第一次來迪魯特，真不敢相信這裡以前有住人。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"한때는 노르드나빅에서 가장 규모가 큰 광산도시였어. 나도 어렸을 땐 잠깐 이곳에서 갱도를 뚫는 기술자로 일했었지.","JPN":"一時はノルドナビックでもっとも大きな鉱山都市だったんだ。俺も若い頃ここで坑道を掘る技術者としてちょっと働いてたんだぞ。","ENG":"This was once Nordnavik's largest mining town. I briefly worked as a tunneling technician here when I was younger.","TWN":"這裡曾經是諾爾德萊比規模最大的礦產都市，我小時候也在這裡當過打通坑道的技術人員。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"그러고보니 와트 씨는 왜 군인이 되신 거예요? 재건단에선 기술자가 많이 필요하다고 들었는데.","JPN":"そういえば、ワットさんってなんで入隊したんですか？　再建団には技術者がもっと必要だって聞きましたけど。","ENG":"Come to think of it, why did you join the army, Mr. Watt? Didn't the Alliance need a lot of technicians or something?","TWN":"那你為什麼會成爲軍人？我聽說重建委員不是需要很多技師嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"처음엔 나도 수도로 가려고 했었어.","JPN":"最初は俺も首都に行こうとしてたさ。","ENG":"I was thinking of heading to the capital once.","TWN":"一開始我也想去首都。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"그런데 피난 도중에 약혼자가 죽었거든. 침식체들한테.","JPN":"でも避難中にフィアンセが死んじまったんだ。侵食体によってな。","ENG":"But during the evacuation, my fiancée got killed by those C.O.s.","TWN":"可是在逃難的途中，未婚妻被侵蝕體害死。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"……몰랐어요.","JPN":"……知りませんでした。","ENG":"I... I didn't know.","TWN":"……我不知道這件事。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"그것 때문에 복수하려고 마음 먹으신 건가요?","JPN":"それで復讐しようと決意したんですか？","ENG":"Is that why you swore to get revenge on them?","TWN":"因爲這樣而下決心報仇嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"물론 침식체가 증오스럽긴 하지만, 침식체 몇 마리 잡는다고 그녀가 편히 잠들 거라 생각하진 않아.","JPN":"もちろん侵食体は憎いが、侵食体を倒したからって彼女が浮かばれるとは思ってねえよ。","ENG":"It's not a secret I despise C.O.s, but I don't think killing a few of them will allow her to rest in peace.","TWN":"雖然我很憎恨侵蝕體，但我不認爲殺幾隻侵蝕體就能讓她安息。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"더 이상 나같은 외톨이가 나와선 안 된다는 각오였어. 그래서 나름 내 기술이 군에 보탬이 될 거라 생각하고 지원했지.","JPN":"もう俺のような一人ぼっちを出さないって覚悟したからだ。それで俺の技術がそれなりに軍の役に立つと思って志願したわけさ。","ENG":"I promised myself that I wouldn't let another person lose their loved one like me. That's why I decided to join and use my skills to help out the army.","TWN":"我下定決心，希望不再有人像我一樣成為孤家寡人，然後覺得我的技術可以對軍隊有幫助，於是就報名從軍。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"뭐, 지휘관님이 나타난 뒤론 내 특기도 별볼일 없어졌지만 말이야.","JPN":"まあ、指揮官が現れてからは、俺の特技もつまらなくなっちまったがな。","ENG":"But, my specialty seems to be no use after our commander joined...","TWN":"不過指揮官出現後，我的專長就變得沒什麼看頭。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"그래도 대포는 누구보다 잘 다루시잖아요. 이번에 지휘관님 지시로 폭탄도 엄청나게 만들었고.","JPN":"でも大砲は誰よりもうまく扱えるじゃないですか。この前は指揮官の指示で爆弾もいっぱい作りましたし。","ENG":"But you're still the best with cannons around here! You even made those incredible explosives on the Commander's orders!","TWN":"但你很會操控大砲的嘛！這次在指揮官的指示下，還製作那麼多炸彈。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"큭큭, 꼴에 걱정해주는 거냐? 내가 자격지심에 시달리기라도 할까봐?","JPN":"ククッ、心配してくれてんのか？　俺が自己嫌悪にでも陥るんじゃないかと？","ENG":"Haha... Are you worrying about me? What? You think I have some sort of inferiority complex?","TWN":"呵呵，你在擔心我嗎？怕我會自卑嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"나 참. 누가 누굴 걱정한다는 거예요. 전 평생 여자친구도 못 사귀어봤다고요.","JPN":"まったく。他人の心配をしてる場合じゃないですよ。僕なんかこれまで付き合ったこともないのに。","ENG":"Huh? Why would I worry about you? I haven't even dated a girl yet.","TWN":"真是的，誰擔心你，我這輩子都沒有交過女朋友呢。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"다들 경계해라. 언제 어디서 침식체가 튀어나올지 모른다.","JPN":"みんな、警戒しろ。いつどこで侵食体が出てくるかわからない。","ENG":"Stay alert, everyone. We don't know when a C.O. will jump out at us.","TWN":"大家要保持警覺，侵蝕體不知何時會冒出來。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"예!","JPN":"はっ！","ENG":"Yes, sir!","TWN":"是！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"신호가 가깝네요. 여기서 그리 멀지 않아요.","JPN":"信号が近いですね。ここからそんなに遠くありません。","ENG":"The signal's strong. It's not that far from here.","TWN":"訊號很接近，離這裡不遠。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"어… 어라? 탐지기가 갑자기 먹통이 됐어요.","JPN":"あ……あれ？　探知機がいきなり反応しなくなりました。","ENG":"W-what? The detector's suddenly not working.","TWN":"呃…呃？探測器突然沒反應！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"고장 난 겁니까?","JPN":"壊れたのですか？","ENG":"Is it broken?","TWN":"壞掉了嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"아니. 침식파 때문에 성유물의 시그니처 패턴을 제대로 못 읽고 있을 뿐이다.","JPN":"いや。侵食波のせいで聖遺物のシグネチャーパターンをちゃんと読み取れていないだけだ。","ENG":"No, it's just not able to read the Holy Relic's signature pattern because of the Corruption ray.","TWN":"沒有，只是因爲侵蝕波的關係，無法順利讀聖遺物的信號模式而已。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"여기서부터는 신호가 닿았던 장소를 중심으로 여러 곳에 침식파 관측망을 설치할 거야.","JPN":"ここからは信号があった場所を中心に、何か所か侵食波の観測網を設置する。","ENG":"From here we will set up a Corruption ray observation network in several locations, with the last location the signal reached serving as the center.","TWN":"從這裡開始，以訊號觸及的地點爲中心，在各處設置侵蝕波監測網。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"침식파를 이용해서 성유물의 위치를 찾으려는 겁니까?","JPN":"侵食波を利用して聖遺物の位置を探すおつもりですか？","ENG":"Are you trying to use the Corruption ray to locate the Holy Relic?","TWN":"你是想利用侵蝕波來尋找聖遺物的位置嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그래, 낙원문과 열쇠는 침식을 막아 주던 물건이니 이걸로 장소를 특정할 수 있을 거다.","JPN":"そうだ、楽園の門と鍵は侵食を食い止めていたものだから、これで場所を特定できるはずだ。","ENG":"Correct. Avalon's Gate and the Key blocked out the Corruption ray, so we'll be able to pinpoint its location with this.","TWN":"沒錯，樂園門和鑰匙都抵擋過侵蝕，用這個應該可以鎖定地點。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"과연. 침식파 계수가 다르게 관측되는 장소에 성유물이 있을 가능성이 높겠군요.","JPN":"なるほど。侵食波の係数が違うところに聖遺物がある可能性は高いですね。","ENG":"I see. So the Holy Relic is likely to be where the Corruption ray is observed differently.","TWN":"果然，聖遺物很可能就在觀測到不同侵蝕波係數的地方。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"이터니움 실드가 얼마나 버텨줄지 몰라요. 서두르는 게 좋겠어요.","JPN":"エタニウムシールドがどれだけ持ってくれるかわかりません。急いだ方がいいですよ。","ENG":"We don't know how long the Eternium shield will hold. It's best if we hurry.","TWN":"不知道永恆之金盾牌能撐多久，最好快點。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"저랑 래시포드 씨가 각자 나눠서 관측기를 설치할게요.","JPN":"私とラッシュフォードさんで分れて、観測器を設置します。","ENG":"Miss Rashford and I will split up and go set up the observation devices.","TWN":"我和雷斯福特分頭設置觀測器。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"다들 들었지?","JPN":"みんな聞いたか？","ENG":"You heard her.","TWN":"大家有聽到嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"실어온 장비들을 꺼내. 분대를 나눠 설치 장소로 이동한다.","JPN":"運んできた装備を取り出せ。分隊に分かれて設置する場所へ移動する。","ENG":"Bring out the equipment. Divide into teams and move to your location.","TWN":"將運來的設備拿出來，分頭前往設置地點。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};